// Public barrel for the BTAvatar component.
//
// Mirrors @buma-dev/buma_design_system's per-component barrel pattern:
// exports the widget + public types so the top-level `btech_ui.dart`
// fan-outs via one line.
export 'avatar.types.dart';
export 'avatar.widget.dart';

// Public types for [BTAvatar] v2.
//
// Data-class API mirrors @buma-dev/buma-ui-v2's UIAvatarItem pattern:
// a single `BTAvatarItem` carries the user payload (name, optional
// imageUrl, optional color override). Cross-framework parity with
// React + Vue.

/// Avatar size — matches the six Figma variants (24/32/40/48/64/96 px).
///
/// Naming uses an abstract scale (xs..xxl) rather than absolute pixels
/// so the design team can tweak ramps without breaking consumer code.
enum BTAvatarSize { xs, sm, md, lg, xl, xxl }

/// Component-specific palette (hardcoded per Figma 497:979).
///
/// Per [Figma visual rule](docs/architecture/figma-visual-rule.md) and
/// [component-specific colors policy](CLAUDE.md), these colors are
/// hardcoded in `internal/avatar.constants.dart` rather than tokenized
/// in `btech_tokens` — they're unique to BTAvatar.
enum BTAvatarColor { green, blue, orange, purple, teal, pink }

/// Explicit override variants from Figma 497:979.
///
///   [error] — renders a `hide_image` icon on [bg/subtler] background.
///             Also triggered automatically when [BTAvatarItem.imageUrl]
///             fails to load (errorBuilder).
///   [empty] — alias for passing no [item]; renders a `person` icon on
///             [bg/subtler] background. Use [BTAvatar] with a null [item]
///             instead of setting this directly.
///
/// Cross-framework parity: Vue/React use `status?: 'error'` string literal.
enum BTAvatarStatus { none, error }

/// Avatar payload — required input to [BTAvatar].
///
/// The [name] field is required and used to derive 1–2 character
/// initials when [imageUrl] is absent or fails to load.
class BTAvatarItem {
  const BTAvatarItem({
    required this.name,
    this.imageUrl,
    this.color = BTAvatarColor.green,
  });

  /// Used to derive initials. e.g. "Faisal Lestari" → "FL".
  final String name;

  /// When provided, renders as Image.network. Falls back to initials on error.
  final String? imageUrl;

  /// Background color for initials variant. Defaults to [BTAvatarColor.green].
  final BTAvatarColor color;
}

/// Derive 1-2 character initials from a person's name.
///
///  * "Faisal Lestari" → "FL"
///  * "Rama"           → "R"
///  * "John Foo Bar"   → "JB" (first + last word)
///  * "" or whitespace → "?"
///
/// Mirrors React/Vue `deriveInitials` exactly.
String deriveInitials(String name) {
  final trimmed = name.trim();
  if (trimmed.isEmpty) return '?';
  final words = trimmed.split(RegExp(r'\s+'));
  if (words.length == 1) return words.first[0].toUpperCase();
  final first = words.first[0];
  final last = words.last[0];
  return (first + last).toUpperCase();
}

/// BTAvatar v2 — circular badge with image, initials, empty, or error state.
///
/// Sliced from Figma `Avatar` (node 497:979). Data-class API mirrors
/// the React/Vue equivalents one-to-one — same prop names, same
/// variant precedence — so designers and devs move between platforms
/// without re-learning component contracts.
///
/// ## Variant precedence (highest first):
///   1. `isLoading == true`              → [BTLoadingSkeleton] shimmer circle
///   2. `status == BTAvatarStatus.error`
///      OR `item.imageUrl` fails to load → `hide_image` icon on [bg/subtler]
///   3. `item == null`                   → `person` icon on [bg/subtler] (empty)
///   4. `item.imageUrl != null`          → Image.network (errorBuilder → error)
///   5. (default)                        → initials on colored background
///
/// ## Usage:
/// ```dart
/// // Initials (default)
/// BTAvatar(item: BTAvatarItem(name: 'Faisal Lestari'), size: BTAvatarSize.md);
///
/// // Image — auto-fallback to error icon on load failure
/// BTAvatar(item: BTAvatarItem(name: 'JD', imageUrl: 'https://...'));
///
/// // Explicit error state (backend signals broken asset)
/// BTAvatar(item: BTAvatarItem(name: 'AB'), status: BTAvatarStatus.error);
///
/// // Empty — no user associated
/// BTAvatar(size: BTAvatarSize.md);
///
/// // Loading skeleton
/// BTAvatar(isLoading: true);
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/loading_skeleton/loading_skeleton.widget.dart';
import 'package:btech_ui/src/components/molecules/avatar/avatar.types.dart';
import 'package:btech_ui/src/components/molecules/avatar/internal/avatar.constants.dart';
import 'package:flutter/material.dart';

/// BTAvatar widget — see file header for variant precedence.
class BTAvatar extends StatelessWidget {
  const BTAvatar({
    this.item,
    this.size = BTAvatarSize.md,
    this.isLoading = false,
    this.status = BTAvatarStatus.none,
    super.key,
  });

  /// Avatar payload. When `null`, renders the empty (person icon) variant.
  final BTAvatarItem? item;

  /// Size ramp — see [BTAvatarSize].
  final BTAvatarSize size;

  /// When `true`, renders a [BTLoadingSkeleton] shimmer placeholder.
  final bool isLoading;

  /// Explicit override to the error variant. Useful when the caller already
  /// knows the asset is unavailable.
  final BTAvatarStatus status;

  @override
  Widget build(BuildContext context) {
    final pxSize = avatarPx[size]!;
    final neutralBg = context.btechColor.bg.subtler;
    final neutralFg = context.btechColor.text.secondary;
    final inverseFg = context.btechColor.text.inverse;

    // 1 — Loading: BTLoadingSkeleton wraps a circle placeholder so Skeletonizer
    //     picks up the shape and animates the shimmer using btech token colors.
    if (isLoading) {
      return BTLoadingSkeleton(
        child: Icon(
          Icons.person,
          size: pxSize,
          color: neutralFg,
        ),
      );
    }

    // 2 — Explicit error override
    if (status == BTAvatarStatus.error) {
      return _iconCircle(
        pxSize: pxSize,
        bg: neutralBg,
        icon: Icons.hide_image_outlined,
        iconColor: neutralFg,
      );
    }

    // 3 — Empty (no item)
    if (item == null) {
      return _iconCircle(
        pxSize: pxSize,
        bg: neutralBg,
        icon: Icons.person,
        iconColor: neutralFg,
      );
    }

    // 4 — Image variant (errorBuilder → error icon)
    if (item!.imageUrl != null && item!.imageUrl!.isNotEmpty) {
      return _circle(
        pxSize,
        avatarPalette[item!.color]!,
        ClipOval(
          child: Image.network(
            item!.imageUrl!,
            width: pxSize,
            height: pxSize,
            fit: BoxFit.cover,
            errorBuilder: (_, __, ___) => _iconCircle(
              pxSize: pxSize,
              bg: neutralBg,
              icon: Icons.hide_image_outlined,
              iconColor: neutralFg,
            ),
          ),
        ),
      );
    }

    // 5 — Initials (default)
    return _circle(
      pxSize,
      avatarPalette[item!.color]!,
      Text(
        deriveInitials(item!.name),
        style: TextStyle(
          color: inverseFg,
          fontSize: fontSizeFor(size),
          fontWeight: FontWeight.w500,
          fontFamily: BTechTypography.fontFamily,
          height: 1,
        ),
      ),
    );
  }

  /// Circle container — colored background + centered child.
  Widget _circle(double pxSize, Color bg, Widget child) => Container(
        width: pxSize,
        height: pxSize,
        alignment: Alignment.center,
        decoration: BoxDecoration(color: bg, shape: BoxShape.circle),
        child: child,
      );

  /// Icon variant — uses ClipOval so the icon is guaranteed to paint inside
  /// the circular clipping boundary (avoids glyph paint-order artefacts).
  Widget _iconCircle({
    required double pxSize,
    required Color bg,
    required IconData icon,
    required Color iconColor,
  }) =>
      ClipOval(
        child: Container(
          width: pxSize,
          height: pxSize,
          color: bg,
          alignment: Alignment.center,
          child: Icon(
            icon,
            size: iconSizeFor(size),
            color: iconColor,
          ),
        ),
      );
}

// Internal constants for [BTAvatar] — not exported from `avatar.dart`.
//
// Kept private (via `internal/` directory) so consumers can't depend
// on raw pixel values that may change with the design system. Mirrors
// buma-ui's `internal/` convention for component-private helpers.
//
// Component-specific avatar palette (6 brand colors) is HARDCODED here
// per the [component-specific colors rule](docs/architecture/figma-
// visual-rule.md). NEVER tokenize one-off palettes.

import 'package:btech_ui/src/components/molecules/avatar/avatar.types.dart';
import 'package:flutter/material.dart';

/// Pixel size of each [BTAvatarSize] — must stay in sync with
/// `BTAvatar.css` (web) and `BTAvatar.vue` (web).
const Map<BTAvatarSize, double> avatarPx = {
  BTAvatarSize.xs: 24,
  BTAvatarSize.sm: 32,
  BTAvatarSize.md: 40,
  BTAvatarSize.lg: 48,
  BTAvatarSize.xl: 64,
  BTAvatarSize.xxl: 96,
};

/// Font size per [BTAvatarSize] — matches Figma 497:979 typography ramp.
double fontSizeFor(BTAvatarSize s) => switch (s) {
      BTAvatarSize.xs => 10,
      BTAvatarSize.sm => 14,
      BTAvatarSize.md => 16,
      BTAvatarSize.lg => 20,
      BTAvatarSize.xl => 28,
      BTAvatarSize.xxl => 40,
    };

/// Stacking offset (negative left margin) per [BTAvatarSize] for
/// [BTAvatarGroup] horizontal overlap. Per Figma 504:705.
double stackOffsetFor(BTAvatarSize s) => switch (s) {
      BTAvatarSize.xs => 8,
      BTAvatarSize.sm => 10,
      BTAvatarSize.md => 12,
      BTAvatarSize.lg => 16,
      BTAvatarSize.xl => 20,
      BTAvatarSize.xxl => 32,
    };

/// Icon size for empty/error variant icons, proportional (~56%) to avatar px.
double iconSizeFor(BTAvatarSize s) => switch (s) {
      BTAvatarSize.xs => 14,
      BTAvatarSize.sm => 18,
      BTAvatarSize.md => 22,
      BTAvatarSize.lg => 26,
      BTAvatarSize.xl => 36,
      BTAvatarSize.xxl => 54,
    };

/// Component-specific brand palette — HARDCODED per Figma 497:979.
/// Do NOT tokenize these (component-specific colors policy).
const Map<BTAvatarColor, Color> avatarPalette = {
  BTAvatarColor.green: Color(0xFF89AE68),
  BTAvatarColor.blue: Color(0xFF93C6EF),
  BTAvatarColor.orange: Color(0xFFFC7B1F),
  BTAvatarColor.purple: Color(0xFF8873BD),
  BTAvatarColor.teal: Color(0xFF2FA0A1),
  BTAvatarColor.pink: Color(0xFFF37A98),
};
